import{_ as r,o as a,c as o,a0 as e}from"./chunks/framework.Dx25mwie.js";const g=JSON.parse('{"title":"西班牙海鮮燉飯（Paella de Marisco）— 主廚秘訣版","description":"西班牙主廚親自教學，不用番紅花也能做出美味海鮮燉飯！Sofrito醬底、自熬海鮮高湯、先爐火後烤箱。","frontmatter":{"title":"西班牙海鮮燉飯（Paella de Marisco）— 主廚秘訣版","description":"西班牙主廚親自教學，不用番紅花也能做出美味海鮮燉飯！Sofrito醬底、自熬海鮮高湯、先爐火後烤箱。"},"headers":[],"relativePath":"docs/西式/西班牙海鮮燉飯_主廚秘訣.md","filePath":"docs/西式/西班牙海鮮燉飯_主廚秘訣.md"}'),l={name:"docs/西式/西班牙海鮮燉飯_主廚秘訣.md"};function d(i,t,n,s,h,c){return a(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="西班牙海鮮燉飯-paella-de-marisco-—-主廚秘訣版" tabindex="-1">西班牙海鮮燉飯（Paella de Marisco）— 主廚秘訣版 <a class="header-anchor" href="#西班牙海鮮燉飯-paella-de-marisco-—-主廚秘訣版" aria-label="Permalink to &quot;西班牙海鮮燉飯（Paella de Marisco）— 主廚秘訣版&quot;">​</a></h1><p><strong>來源：</strong> <a href="https://youtu.be/TSe3nAu5v9M" target="_blank" rel="noreferrer">YouTube - HolaSpain島男西文</a><strong>分享日期：</strong> 2026/06/08 <strong>語言：</strong> 西班牙語（有中文字幕）</p><hr><h2 id="這支影片的特色" tabindex="-1">這支影片的特色 <a class="header-anchor" href="#這支影片的特色" aria-label="Permalink to &quot;這支影片的特色&quot;">​</a></h2><blockquote><p>西班牙主廚親自教學，不添加番紅花也能做出美味海鮮燉飯！</p></blockquote><hr><h2 id="📝-食譜重點" tabindex="-1">📝 食譜重點 <a class="header-anchor" href="#📝-食譜重點" aria-label="Permalink to &quot;📝 食譜重點&quot;">​</a></h2><h3 id="_1️⃣-sofrito-醬底-—-風味的基礎" tabindex="-1">1️⃣ Sofrito（醬底）— 風味的基礎 <a class="header-anchor" href="#_1️⃣-sofrito-醬底-—-風味的基礎" aria-label="Permalink to &quot;1️⃣ Sofrito（醬底）— 風味的基礎&quot;">​</a></h3><table tabindex="0"><thead><tr><th>材料</th><th>說明</th></tr></thead><tbody><tr><td>洋蔥碎</td><td>先爆香</td></tr><tr><td>紅椒</td><td>切碎加入</td></tr><tr><td>青椒</td><td>切碎加入</td></tr></tbody></table><blockquote><p>可<strong>前一天先做好</strong>，隔天再完成燉飯</p></blockquote><h3 id="_2️⃣-高湯-caldo-—-最關鍵的一步" tabindex="-1">2️⃣ 高湯（Caldo）— 最關鍵的一步 <a class="header-anchor" href="#_2️⃣-高湯-caldo-—-最關鍵的一步" aria-label="Permalink to &quot;2️⃣ 高湯（Caldo）— 最關鍵的一步&quot;">​</a></h3><ul><li>用<strong>蝦殼、海鮮殼</strong>熬煮高湯</li><li>高湯是燉飯好吃的靈魂</li><li>建議自熬，不要用水代替</li></ul><h3 id="_3️⃣-米與高湯比例" tabindex="-1">3️⃣ 米與高湯比例 <a class="header-anchor" href="#_3️⃣-米與高湯比例" aria-label="Permalink to &quot;3️⃣ 米與高湯比例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>材料</th><th>比例</th></tr></thead><tbody><tr><td>🔸 米</td><td><strong>4 份</strong></td></tr><tr><td>🔹 高湯</td><td><strong>8 份</strong> 標準比例</td></tr><tr><td>🔹 實際用量</td><td><strong>7 份</strong>（因 sofrito 本身含水分）</td></tr></tbody></table><h3 id="_4️⃣-祕密食材" tabindex="-1">4️⃣ 祕密食材 <a class="header-anchor" href="#_4️⃣-祕密食材" aria-label="Permalink to &quot;4️⃣ 祕密食材&quot;">​</a></h3><ul><li>🍅 <strong>番茄</strong> — 增添色澤與風味，代替番紅花</li><li>🍷 <strong>白酒</strong> — 用料理用白酒烹調</li><li>🧂 <strong>不加鹽</strong> — 海鮮與醬底本身風味已夠濃郁</li></ul><h3 id="_5️⃣-烹調步驟" tabindex="-1">5️⃣ 烹調步驟 <a class="header-anchor" href="#_5️⃣-烹調步驟" aria-label="Permalink to &quot;5️⃣ 烹調步驟&quot;">​</a></h3><ol><li>先做 <strong>Sofrito</strong>（洋蔥+紅椒+青椒炒軟）</li><li>加入<strong>番茄</strong>增加色澤</li><li>倒入<strong>白酒</strong>拌炒</li><li>加入<strong>高湯</strong>（米與高湯約 4:7）</li><li>放入<strong>海鮮</strong>（蝦、蛤蜊等，先處理好去殼）</li><li>爐火先煮一陣</li><li>進 <strong>200°C 烤箱</strong>烤至完成</li></ol><h3 id="_6️⃣-主廚小撇步" tabindex="-1">6️⃣ 主廚小撇步 <a class="header-anchor" href="#_6️⃣-主廚小撇步" aria-label="Permalink to &quot;6️⃣ 主廚小撇步&quot;">​</a></h3><ul><li>🦐 <strong>海鮮先去殼</strong> — 讓客人吃的時候更方便，不用動手剝</li><li>📅 <strong>Sofrito 可提前備</strong> — 分天做更輕鬆</li><li>🌡️ <strong>先爐火後烤箱</strong> — 米粒口感更佳</li><li>🚫 <strong>不塗番紅花</strong>也能做出漂亮色澤</li></ul><hr><h2 id="食材清單-整理" tabindex="-1">食材清單（整理） <a class="header-anchor" href="#食材清單-整理" aria-label="Permalink to &quot;食材清單（整理）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>類別</th><th>食材</th></tr></thead><tbody><tr><td>🥬 蔬菜</td><td>洋蔥、紅椒、青椒、番茄</td></tr><tr><td>🦐 海鮮</td><td>蝦、蛤蜊（或其他海鮮）</td></tr><tr><td>🍚 主食</td><td>燉飯專用米（如 Bomba 米）</td></tr><tr><td>🧂 調味</td><td>白酒（料理用）、橄欖油</td></tr><tr><td>🥣 高湯</td><td>自熬海鮮高湯</td></tr></tbody></table><hr><p><em>由 Hermes 於 2026/06/08 整理</em></p>',25)])])}const b=r(l,[["render",d]]);export{g as __pageData,b as default};
